import type { DemoStep } from './types'

const BASE_URL = 'http://localhost:8080'

export const steps: DemoStep[] = [
  {
    title: 'Welcome',
    description: 'This is College Power Search — a faceted search engine for U.S. colleges.',
    action: async (page) => {
      await page.goto(BASE_URL, { waitUntil: 'networkidle' })
      // Scroll to make sure the hero is fully visible
      await page.evaluate(() => window.scrollTo({ top: 0, behavior: 'smooth' }))
    },
  },

  {
    title: 'Quick Search',
    description: 'Type a college name into the search box to start narrowing results.',
    action: async (page) => {
      const input = page.locator('input[type="search"]')
      await input.scrollIntoViewIfNeeded()
      await input.click()
      await input.type('Stanford', { delay: 80 })
    },
  },

  {
    title: 'Add Filters',
    description: 'Use the dropdowns to filter by state and ranking tier.',
    action: async (page) => {
      // Select California from the state dropdown
      const stateSelect = page.locator('select').filter({ hasText: 'Any state' })
      await stateSelect.selectOption('CA')
      await page.waitForTimeout(400)

      // Select Top 50 ranking
      const rankSelect = page.locator('select').filter({ hasText: 'Any rank' })
      await rankSelect.selectOption('50')
    },
  },

  {
    title: 'Submit Search',
    description: 'Click "Search" to see matching institutions on the results page.',
    action: async (page) => {
      await page.locator('button[type="submit"]:has-text("Search")').click()
      await page.waitForURL('**/search?**', { timeout: 10000 })
      // Wait for results table to load
      await page.waitForSelector('table', { timeout: 10000 }).catch(() => {
        // Results may be empty — that's OK for the demo
      })
    },
  },

  {
    title: 'Browse Results',
    description: 'Results appear in a data table with name, city, state, and more columns.',
    action: async (page) => {
      const table = page.locator('table')
      await table.scrollIntoViewIfNeeded()
      // Highlight rows one by one
      await page.evaluate(async () => {
        const rows = document.querySelectorAll('table tbody tr')
        for (const row of rows) {
          ;(row as HTMLElement).style.transition = 'background-color 0.3s'
          ;(row as HTMLElement).style.backgroundColor = 'rgba(201, 162, 39, 0.15)'
          await new Promise((r) => setTimeout(r, 400))
          ;(row as HTMLElement).style.backgroundColor = ''
        }
      })
    },
  },

  {
    title: 'Ranking Blend',
    description: 'Create a custom ranking by weighting multiple ranking providers together.',
    action: async (page) => {
      await page.goto(`${BASE_URL}/search`, { waitUntil: 'networkidle' })
      await page.waitForTimeout(500)

      const blendSection = page.locator('[data-testid="ranking-blend-builder"]')
      if (await blendSection.isVisible().catch(() => false)) {
        await blendSection.scrollIntoViewIfNeeded()
        await page.waitForTimeout(300)

        // Highlight the blend builder area
        await page.evaluate(() => {
          const section = document.querySelector('[data-testid="ranking-blend-builder"]')
          if (!section) return
          ;(section as HTMLElement).style.transition = 'box-shadow 0.3s'
          ;(section as HTMLElement).style.boxShadow = '0 0 0 3px rgba(201, 162, 39, 0.5)'
          setTimeout(() => {
            ;(section as HTMLElement).style.boxShadow = ''
          }, 2500)
        })
        await page.waitForTimeout(2500)
      }
    },
  },

  {
    title: 'Column Picker',
    description: 'Use the Columns button to show or hide data columns in the results table.',
    action: async (page) => {
      const columnsButton = page.locator('button:has-text("Columns")')
      if (await columnsButton.isVisible().catch(() => false)) {
        await columnsButton.click()
        await page.waitForTimeout(800)
        // Highlight the popover briefly
        await page.evaluate(() => {
          const dropdown = document.querySelector('[data-mantine-component="PopoverDropdown"]')
          if (!dropdown) return
          ;(dropdown as HTMLElement).style.transition = 'box-shadow 0.3s'
          ;(dropdown as HTMLElement).style.boxShadow = '0 0 0 3px rgba(201, 162, 39, 0.5)'
          setTimeout(() => {
            ;(dropdown as HTMLElement).style.boxShadow = ''
          }, 2000)
        })
        await page.waitForTimeout(2000)
        // Close the popover by clicking outside
        await page.locator('h2:has-text("Results")').click()
      }
    },
  },

  {
    title: 'Filter Sidebar',
    description: 'The sidebar lets you add or change filters to refine your search.',
    action: async (page) => {
      // Scroll to the top to show the filter sidebar
      await page.evaluate(() => window.scrollTo({ top: 0, behavior: 'smooth' }))
      await page.waitForTimeout(300)
      // Highlight the "Filters" heading area
      await page.evaluate(() => {
        const filtersHeading = Array.from(document.querySelectorAll('h6')).find(
          (h) => h.textContent?.toLowerCase().includes('filters'),
        )
        const sidebar = filtersHeading?.closest('div[style*="width"]')
        if (sidebar) {
          ;(sidebar as HTMLElement).style.transition = 'box-shadow 0.3s'
          ;(sidebar as HTMLElement).style.boxShadow = '0 0 0 3px rgba(201, 162, 39, 0.5)'
          setTimeout(() => {
            ;(sidebar as HTMLElement).style.boxShadow = ''
          }, 2000)
        }
      })
    },
  },

  {
    title: 'Pagination',
    description: 'Navigate between pages of results and change the number shown per page.',
    action: async (page) => {
      const pagination = page.locator('[data-testid="pagination-controls"]')
      const isVisible = await pagination.isVisible().catch(() => false)
      if (isVisible) {
        await pagination.scrollIntoViewIfNeeded()
        // Highlight pagination area
        await page.evaluate(() => {
          const el = document.querySelector('[data-testid="pagination-controls"]')
          if (!el) return
          ;(el as HTMLElement).style.transition = 'box-shadow 0.3s'
          ;(el as HTMLElement).style.boxShadow = '0 0 0 3px rgba(201, 162, 39, 0.5)'
          setTimeout(() => {
            ;(el as HTMLElement).style.boxShadow = ''
          }, 2000)
        })
        // Try clicking page 2 if available
        const page2 = pagination.locator('button:has-text("2")')
        if (await page2.isVisible().catch(() => false)) {
          await page2.click()
          await page.waitForTimeout(1000)
        }
      } else {
        // Not enough results for pagination — just note it
        await page.evaluate(() => {
          const main = document.querySelector('main')
          if (!main) return
          const note = document.createElement('div')
          note.textContent = '(Not enough results to show pagination — try a broader search)'
          note.style.cssText =
            'padding:12px;margin-top:12px;background:rgba(201,162,39,0.1);border-radius:8px;font-size:13px;color:#666'
          main.appendChild(note)
        })
      }
    },
  },

  {
    title: 'Sample Searches',
    description: 'Back on the home page, pre-built sample searches help you explore quickly.',
    action: async (page) => {
      await page.goto(BASE_URL, { waitUntil: 'networkidle' })
      // Scroll to the sample searches carousel
      const carousel = page.locator('text=Explore Sample Searches')
      await carousel.scrollIntoViewIfNeeded()
      await page.waitForTimeout(500)
      // Click the first sample search card
      const firstCard = page.locator('[data-testid="sample-search-card"]').first()
      if (await firstCard.isVisible().catch(() => false)) {
        await firstCard.click()
        await page.waitForURL('**/search?**', { timeout: 10000 }).catch(() => {})
        await page.waitForTimeout(1000)
      } else {
        // Try clicking the first link inside the carousel section
        const link = page
          .locator('section')
          .filter({ hasText: 'Explore Sample Searches' })
          .locator('a')
          .first()
        if (await link.isVisible().catch(() => false)) {
          await link.click()
          await page.waitForURL('**/search?**', { timeout: 10000 }).catch(() => {})
          await page.waitForTimeout(1000)
        }
      }
    },
  },

  {
    title: 'About Page',
    description: 'The About page describes data sources, methodology, and project goals.',
    action: async (page) => {
      // Click "About" in the header nav
      await page.locator('header a:has-text("About")').click()
      await page.waitForURL('**/about', { timeout: 5000 })
      await page.waitForTimeout(500)
      // Scroll down slowly to show the content
      await page.evaluate(async () => {
        const maxScroll = document.documentElement.scrollHeight - window.innerHeight
        const steps = 5
        for (let i = 1; i <= steps; i++) {
          window.scrollTo({ top: (maxScroll / steps) * i, behavior: 'smooth' })
          await new Promise((r) => setTimeout(r, 600))
        }
      })
    },
  },

  // ── Responsive views ──────────────────────────────────────────────────────

  {
    title: 'Tablet View',
    description: 'The layout adapts to tablet-sized screens (768px wide).',
    action: async (page) => {
      await page.setViewportSize({ width: 768, height: 1024 })
      await page.goto(BASE_URL, { waitUntil: 'networkidle' })
      await page.waitForTimeout(500)
      // Scroll to show the hero and feature cards
      await page.evaluate(async () => {
        const maxScroll = Math.min(
          document.documentElement.scrollHeight - window.innerHeight,
          1200,
        )
        window.scrollTo({ top: maxScroll, behavior: 'smooth' })
        await new Promise((r) => setTimeout(r, 800))
        window.scrollTo({ top: 0, behavior: 'smooth' })
      })
    },
  },

  {
    title: 'Tablet Search',
    description: 'The search page stacks filters above results on tablet.',
    action: async (page) => {
      await page.goto(`${BASE_URL}/search?q=Stanford&state=CA`, { waitUntil: 'networkidle' })
      await page.waitForTimeout(500)
      // Click the Show Filters button to reveal collapsible filters
      const filterToggle = page.locator('button:has-text("Show Filters")')
      if (await filterToggle.isVisible().catch(() => false)) {
        await filterToggle.click()
        await page.waitForTimeout(800)
        // Close filters again
        const hideFilters = page.locator('button:has-text("Hide Filters")')
        if (await hideFilters.isVisible().catch(() => false)) {
          await hideFilters.click()
          await page.waitForTimeout(400)
        }
      }
    },
  },

  {
    title: 'Mobile View',
    description: 'On smartphone screens (375px), the layout is fully single-column.',
    action: async (page) => {
      await page.setViewportSize({ width: 375, height: 812 })
      await page.goto(BASE_URL, { waitUntil: 'networkidle' })
      await page.waitForTimeout(500)
      // Show the mobile navigation drawer
      const burger = page.locator('button[aria-label="Toggle navigation"]')
      if (await burger.isVisible().catch(() => false)) {
        await burger.click()
        await page.waitForTimeout(1000)
        // Close it
        const closeButton = page.locator('[role="dialog"] button[aria-label="Close"]')
        if (await closeButton.isVisible().catch(() => false)) {
          await closeButton.click()
          await page.waitForTimeout(400)
        }
      }
    },
  },

  {
    title: 'Mobile Search',
    description: 'Search results use the full width, with a collapsible filter toggle.',
    action: async (page) => {
      await page.goto(`${BASE_URL}/search?q=MIT`, { waitUntil: 'networkidle' })
      await page.waitForTimeout(500)
      // Show the filter toggle
      const filterToggle = page.locator('button:has-text("Show Filters")')
      if (await filterToggle.isVisible().catch(() => false)) {
        await filterToggle.click()
        await page.waitForTimeout(800)
        // Scroll through filters
        await page.evaluate(async () => {
          window.scrollTo({ top: 200, behavior: 'smooth' })
          await new Promise((r) => setTimeout(r, 600))
        })
        // Close filters
        const hideFilters = page.locator('button:has-text("Hide Filters")')
        if (await hideFilters.isVisible().catch(() => false)) {
          await hideFilters.click()
          await page.waitForTimeout(400)
        }
      }
    },
  },

  {
    title: 'Demo Complete',
    description:
      "That's College Power Search! A responsive, faceted search engine for every U.S. institution.",
    action: async (page) => {
      // Restore desktop viewport
      await page.setViewportSize({ width: 1280, height: 800 })
      await page.goto(BASE_URL, { waitUntil: 'networkidle' })
    },
  },
]

