import type { DemoStep } from './types'

export const BASE_URL = 'http://localhost:8080'

export const steps: DemoStep[] = [
  {
    title: 'Welcome',
    description: 'This is College Power Search — a faceted search engine for U.S. colleges.',
    action: async (page) => {
      await page.goto('/', { waitUntil: 'networkidle' })
      // Scroll to make sure the hero is fully visible
      await page.evaluate(() => window.scrollTo({ top: 0, behavior: 'smooth' }))
    },
  },

import { SegmentedControl } from '@mantine/core'
import { LayoutGrid, List, Map, Table2 } from 'lucide-react'

export type ViewMode = 'card' | 'list' | 'table' | 'map'

interface ViewToggleProps {
  value: ViewMode
  onChange: (mode: ViewMode) => void
}

const VIEW_OPTIONS = [
  { value: 'card', label: <LayoutGrid size={16} aria-hidden /> },
  { value: 'list', label: <List size={16} aria-hidden /> },
  { value: 'table', label: <Table2 size={16} aria-hidden /> },
  { value: 'map', label: <Map size={16} aria-hidden /> },
]

export function ViewToggle({ value, onChange }: ViewToggleProps) {
  return (
    <SegmentedControl
      size="xs"
      value={value}
      onChange={(v) => onChange(v as ViewMode)}
      data={VIEW_OPTIONS}
      aria-label="View mode"
    />
  )
}

import { describe, it, expect, vi } from 'vitest'
import { screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { renderWithMantine } from '@/test/render'
import { ViewToggle, type ViewMode } from './ViewToggle'

describe('ViewToggle', () => {
  it('renders four segments', () => {
    renderWithMantine(<ViewToggle value="card" onChange={() => {}} />)
    const control = screen.getByRole('radiogroup', { name: /view mode/i })
    expect(control).toBeInTheDocument()
    const radios = screen.getAllByRole('radio')
    expect(radios).toHaveLength(4)
  })

  it('has the correct value selected', () => {
    renderWithMantine(<ViewToggle value="list" onChange={() => {}} />)
    const radios = screen.getAllByRole('radio')
    const listRadio = radios.find((r) => r.getAttribute('value') === 'list')
    expect(listRadio).toBeDefined()
    // Mantine marks the active radio with aria-checked or checked state
    expect(listRadio).toBeChecked()
  })

  it('calls onChange when clicking a different segment', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithMantine(<ViewToggle value="card" onChange={onChange} />)
    const radios = screen.getAllByRole('radio')
    const tableRadio = radios.find((r) => r.getAttribute('value') === 'table')!
    await user.click(tableRadio)
    expect(onChange).toHaveBeenCalledWith('table' as ViewMode)
  })
})

